package main


import (
	"fmt"
        "strings"
)

func main() {
    var stack []string

    str := ""
    for _, r := range str {
        c := string(r)
   
        if (len(stack) == 0) {
	   stack = append(stack, c)  
	} else {
	   n := len(stack) - 1	 
	   top := stack[n]
		
	   if (top == c) {
	       stack = append(stack, c)   //push
	   } else {
	       if strings.EqualFold(top, c) {
		  stack = stack[:n]
	       } else {
		  stack = append(stack, c)  
	       }
	   }
	}
    }
    
   fmt.Print(len(stack))  //peek top

}



    
